import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from 'react-query';
import { Toaster } from 'react-hot-toast';

// Contexts
import { AuthProvider } from './contexts/AuthContext';
import { VaultProvider } from './contexts/VaultContext';
import { AdminProvider } from './contexts/AdminContext';

// Components
import ProtectedRoute from './components/auth/ProtectedRoute';
import AdminRoute from './components/auth/AdminRoute';
import UserLayout from './components/layout/UserLayout';
import AdminLayout from './components/layout/AdminLayout';

// Pages
import Login from './pages/auth/Login';
import Register from './pages/auth/Register';
import Dashboard from './pages/Dashboard';
import Vault from './pages/Vault';
import Generator from './pages/Generator';
import SecurityReport from './pages/SecurityReport';
import Settings from './pages/Settings';
import PasswordForm from './pages/PasswordForm';

// Admin Pages
import AdminLogin from './pages/admin/AdminLogin';
import AdminDashboard from './pages/admin/AdminDashboard';
import UserManagement from './pages/admin/UserManagement';
import SystemStats from './pages/admin/SystemStats';
import AdminSettings from './pages/admin/AdminSettings';

// Create a client
const queryClient = new QueryClient({
  defaultOptions: {
    queries: {
      retry: 1,
      refetchOnWindowFocus: false,
    },
  },
});

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AuthProvider>
        <VaultProvider>
          <AdminProvider>
            <Router>
              <div className="App">
                <Routes>
                  {/* Public Routes */}
                  <Route path="/login" element={<Login />} />
                  <Route path="/register" element={<Register />} />
                  <Route path="/admin/login" element={<AdminLogin />} />
                  
                  <Route path="/" element={
                    <div style={{ padding: '20px', textAlign: 'center' }}>
                      <h1>SecureVault React App</h1>
                      <p>🎉 App is working! Complete authentication, vault, and admin system is ready.</p>
                      <div style={{ padding: '20px', background: '#f0f0f0', margin: '20px', borderRadius: '8px' }}>
                        <h2>✅ All Features Available:</h2>
                        <ul style={{ textAlign: 'left', maxWidth: '500px', margin: '0 auto' }}>
                          <li>✅ Authentication System (Login/Register)</li>
                          <li>✅ Protected User Routes</li>
                          <li>✅ Dashboard with Layout</li>
                          <li>✅ Password Vault Management</li>
                          <li>✅ Password Generator</li>
                          <li>✅ Security Reports</li>
                          <li>✅ Settings Page</li>
                          <li>✅ Admin Panel (Login/Dashboard/Users/Stats)</li>
                          <li>✅ PWA Support</li>
                          <li>✅ Toast Notifications</li>
                        </ul>
                        <p><strong>🎯 Status:</strong> Complete SecureVault application is loaded!</p>
                        <div style={{ marginTop: '20px' }}>
                          <a href="/login" style={{ 
                            color: 'white', 
                            background: '#007bff', 
                            padding: '10px 20px', 
                            borderRadius: '5px', 
                            textDecoration: 'none',
                            marginRight: '10px'
                          }}>
                            User Login
                          </a>
                          <a href="/register" style={{ 
                            color: 'white', 
                            background: '#28a745', 
                            padding: '10px 20px', 
                            borderRadius: '5px', 
                            textDecoration: 'none',
                            marginRight: '10px'
                          }}>
                            Register
                          </a>
                          <a href="/admin/login" style={{ 
                            color: 'white', 
                            background: '#dc3545', 
                            padding: '10px 20px', 
                            borderRadius: '5px', 
                            textDecoration: 'none',
                            marginRight: '10px'
                          }}>
                            Admin Login
                          </a>
                          <a href="/dashboard" style={{ 
                            color: 'white', 
                            background: '#6c757d', 
                            padding: '10px 20px', 
                            borderRadius: '5px', 
                            textDecoration: 'none'
                          }}>
                            Dashboard
                          </a>
                        </div>
                      </div>
                    </div>
                  } />

                  {/* Protected User Routes */}
                  <Route
                    path="/dashboard"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <Dashboard />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/vault"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <Vault />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/generator"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <Generator />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/security"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <SecurityReport />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/settings"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <Settings />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />
                  <Route
                    path="/password/new"
                    element={
                      <ProtectedRoute>
                        <UserLayout>
                          <PasswordForm />
                        </UserLayout>
                      </ProtectedRoute>
                    }
                  />

                  {/* Protected Admin Routes */}
                  <Route
                    path="/admin"
                    element={
                      <AdminRoute>
                        <AdminLayout>
                          <AdminDashboard />
                        </AdminLayout>
                      </AdminRoute>
                    }
                  />
                  <Route
                    path="/admin/users"
                    element={
                      <AdminRoute>
                        <AdminLayout>
                          <UserManagement />
                        </AdminLayout>
                      </AdminRoute>
                    }
                  />
                  <Route
                    path="/admin/stats"
                    element={
                      <AdminRoute>
                        <AdminLayout>
                          <SystemStats />
                        </AdminLayout>
                      </AdminRoute>
                    }
                  />
                  <Route
                    path="/admin/settings"
                    element={
                      <AdminRoute>
                        <AdminLayout>
                          <AdminSettings />
                        </AdminLayout>
                      </AdminRoute>
                    }
                  />

                  <Route path="*" element={<Navigate to="/" replace />} />
                </Routes>

                {/* Toast notifications */}
                <Toaster
                  position="top-right"
                  toastOptions={{
                    duration: 4000,
                    style: {
                      background: '#363636',
                      color: '#fff',
                    },
                    success: {
                      duration: 3000,
                      iconTheme: {
                        primary: '#10b981',
                        secondary: '#fff',
                      },
                    },
                    error: {
                      duration: 5000,
                      iconTheme: {
                        primary: '#ef4444',
                        secondary: '#fff',
                      },
                    },
                  }}
                />
              </div>
            </Router>
          </AdminProvider>
        </VaultProvider>
      </AuthProvider>
    </QueryClientProvider>
  );
}

export default App;
